@page "/apply"
@using sv_fe12810a9dfe4bd5b5193129805cf2a3.Models
@inject IApplicationService AppService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h2 class="mb-4">Job Application</h2>

    @* ── Step Indicator Bar ── *@
    <nav class="step-indicator mb-4">
        @for (int i = 0; i < StepLabels.Length; i++)
        {
            var step = i + 1;
            var state = step < _currentStep ? "completed"
                      : step == _currentStep ? "active"
                      : "future";
            <button class="step-item @state"
                    disabled="@(state == "future" || _submitted)"
                    @onclick="() => GoToStep(step)">
                <span class="step-circle">
                    @if (state == "completed")
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        @step
                    }
                </span>
                <span class="step-label">@StepLabels[step - 1]</span>
            </button>

            @if (step < StepLabels.Length)
            {
                <div class="step-connector @state"></div>
            }
        }
    </nav>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger">@_errorMessage</div>
    }

    @* ── Step 1: Personal Info ── *@
    @if (_currentStep == 1)
    {
        <div class="card step-card">
            <div class="card-body">
                <h4 class="card-title">Personal Information</h4>
                <div class="mb-3">
                    <label class="form-label">Full Name <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="_fullName" placeholder="John Doe" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="_email" placeholder="john@example.com" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" @bind="_phone" placeholder="(555) 123-4567" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Address <span class="text-danger">*</span></label>
                    <textarea class="form-control" rows="2" @bind="_address" placeholder="123 Main St, City, State ZIP"></textarea>
                </div>
                <div class="d-flex justify-content-end">
                    <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@_isValidating">
                        @if (_isValidating)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                            <span>Validating…</span>
                        }
                        else
                        {
                            <span>Next &raquo;</span>
                        }
                    </button>
                </div>
            </div>
        </div>
    }

    @* ── Step 2: Work History ── *@
    @if (_currentStep == 2)
    {
        <div class="card step-card">
            <div class="card-body">
                <h4 class="card-title">Work History</h4>

                @for (int i = 0; i < _workEntries.Count; i++)
                {
                    var idx = i;
                    var entry = _workEntries[idx];
                    <div class="work-entry-card mb-3 p-3 border rounded">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Position @(idx + 1)</h6>
                            @if (_workEntries.Count > 1)
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                            }
                        </div>
                        <div class="row g-3">
                            <div class="col-md-6">
                                <label class="form-label">Company <span class="text-danger">*</span></label>
                                <input class="form-control" value="@entry.Company"
                                       @onchange="e => UpdateWorkEntry(idx, entry with { Company = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                                <input class="form-control" value="@entry.Title"
                                       @onchange="e => UpdateWorkEntry(idx, entry with { Title = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-4">
                                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                <input type="date" class="form-control" value="@FormatDate(entry.StartDate)"
                                       @onchange="e => UpdateWorkEntry(idx, entry with { StartDate = ParseDate(e.Value) })" />
                            </div>
                            <div class="col-md-4">
                                <label class="form-label">End Date</label>
                                <input type="date" class="form-control" value="@FormatDate(entry.EndDate)"
                                       disabled="@entry.IsCurrent"
                                       @onchange="e => UpdateWorkEntry(idx, entry with { EndDate = ParseNullableDate(e.Value) })" />
                            </div>
                            <div class="col-md-4 d-flex align-items-end">
                                <div class="form-check mb-2">
                                    <input type="checkbox" class="form-check-input" id="@($"current-{idx}")"
                                           checked="@entry.IsCurrent"
                                           @onchange="e => UpdateWorkEntry(idx, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                                    <label class="form-check-label" for="@($"current-{idx}")">Currently working here</label>
                                </div>
                            </div>
                            <div class="col-12">
                                <label class="form-label">Description <span class="text-danger">*</span></label>
                                <textarea class="form-control" rows="2" value="@entry.Description"
                                          @onchange="e => UpdateWorkEntry(idx, entry with { Description = (string?)e.Value ?? string.Empty })"></textarea>
                            </div>
                        </div>
                    </div>
                }

                <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">
                    &#43; Add Another Position
                </button>

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="PreviousStep">&laquo; Back</button>
                    <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next &raquo;</button>
                </div>
            </div>
        </div>
    }

    @* ── Step 3: References ── *@
    @if (_currentStep == 3)
    {
        <div class="card step-card">
            <div class="card-body">
                <h4 class="card-title">References</h4>
                <p class="text-muted">Please provide 2–3 professional references.</p>

                @for (int i = 0; i < _references.Count; i++)
                {
                    var idx = i;
                    var r = _references[idx];
                    <div class="reference-card mb-3 p-3 border rounded">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Reference @(idx + 1)</h6>
                            @if (_references.Count > 2)
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(idx)">Remove</button>
                            }
                        </div>
                        <div class="row g-3">
                            <div class="col-md-6">
                                <label class="form-label">Name <span class="text-danger">*</span></label>
                                <input class="form-control" value="@r.Name"
                                       @onchange="e => UpdateReference(idx, r with { Name = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                <input class="form-control" value="@r.Relationship"
                                       @onchange="e => UpdateReference(idx, r with { Relationship = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Email <span class="text-danger">*</span></label>
                                <input type="email" class="form-control" value="@r.Email"
                                       @onchange="e => UpdateReference(idx, r with { Email = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Phone <span class="text-danger">*</span></label>
                                <input type="tel" class="form-control" value="@r.Phone"
                                       @onchange="e => UpdateReference(idx, r with { Phone = (string?)e.Value ?? string.Empty })" />
                            </div>
                        </div>
                    </div>
                }

                @if (_references.Count < 3)
                {
                    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
                        &#43; Add Reference
                    </button>
                }

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="PreviousStep">&laquo; Back</button>
                    <button class="btn btn-primary" @onclick="NextFromReferences">Next &raquo;</button>
                </div>
            </div>
        </div>
    }

    @* ── Step 4: Cover Letter ── *@
    @if (_currentStep == 4)
    {
        <div class="card step-card">
            <div class="card-body">
                <h4 class="card-title">Cover Letter</h4>
                <div class="mb-2">
                    <textarea class="form-control" rows="10" maxlength="2000"
                              @bind="_coverLetter" placeholder="Tell us why you're a great fit…"></textarea>
                </div>
                <div class="text-muted mb-3 text-end">
                    @(_coverLetter?.Length ?? 0) / 2000 characters
                </div>
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="PreviousStep">&laquo; Back</button>
                    <button class="btn btn-primary" @onclick="NextFromCoverLetter">Next &raquo;</button>
                </div>
            </div>
        </div>
    }

    @* ── Step 5: Review & Submit ── *@
    @if (_currentStep == 5 && !_submitted)
    {
        <div class="card step-card">
            <div class="card-body">
                <h4 class="card-title">Review &amp; Submit</h4>

                @* Personal Info *@
                <div class="review-section mb-4">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Personal Information</h5>
                        <button class="btn btn-link btn-sm" @onclick='() => GoToStep(1)'>Edit</button>
                    </div>
                    <dl class="row mb-0">
                        <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@_fullName</dd>
                        <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@_email</dd>
                        <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@_phone</dd>
                        <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@_address</dd>
                    </dl>
                </div>

                @* Work History *@
                <div class="review-section mb-4">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Work History</h5>
                        <button class="btn btn-link btn-sm" @onclick='() => GoToStep(2)'>Edit</button>
                    </div>
                    @foreach (var w in _workEntries)
                    {
                        <div class="mb-2 ps-2 border-start border-3">
                            <strong>@w.Title</strong> at <strong>@w.Company</strong><br />
                            <small class="text-muted">
                                @w.StartDate.ToString("MMM yyyy") – @(w.IsCurrent ? "Present" : w.EndDate?.ToString("MMM yyyy"))
                            </small>
                            <p class="mb-0 mt-1">@w.Description</p>
                        </div>
                    }
                </div>

                @* References *@
                <div class="review-section mb-4">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>References</h5>
                        <button class="btn btn-link btn-sm" @onclick='() => GoToStep(3)'>Edit</button>
                    </div>
                    @foreach (var r in _references)
                    {
                        <div class="mb-2 ps-2 border-start border-3">
                            <strong>@r.Name</strong> (@r.Relationship)<br />
                            <small>@r.Email &middot; @r.Phone</small>
                        </div>
                    }
                </div>

                @* Cover Letter *@
                <div class="review-section mb-4">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Cover Letter</h5>
                        <button class="btn btn-link btn-sm" @onclick='() => GoToStep(4)'>Edit</button>
                    </div>
                    <p class="mb-0" style="white-space: pre-wrap;">@_coverLetter</p>
                </div>

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="PreviousStep">&laquo; Back</button>
                    <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isSubmitting">
                        @if (_isSubmitting)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                            <span>Submitting…</span>
                        }
                        else
                        {
                            <span>Submit Application</span>
                        }
                    </button>
                </div>
            </div>
        </div>
    }

    @* ── Confirmation ── *@
    @if (_submitted)
    {
        <div class="card step-card border-success">
            <div class="card-body text-center py-5">
                <div class="text-success mb-3" style="font-size: 3rem;">&#10003;</div>
                <h3 class="text-success">Application Submitted!</h3>
                <p class="lead">Your application ID is <strong>#@_applicationId</strong></p>
                <p class="text-muted">We'll review your application and get back to you soon.</p>
            </div>
        </div>
    }
</div>

@code {
    private static readonly string[] StepLabels = ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private int _currentStep = 1;
    private int _highestCompletedStep;
    private string? _errorMessage;

    // Step 1
    private string _fullName = string.Empty;
    private string _email = string.Empty;
    private string _phone = string.Empty;
    private string _address = string.Empty;
    private bool _isValidating;

    // Step 2
    private List<WorkEntryModel> _workEntries = [new()];

    // Step 3
    private List<ReferenceModel> _references = [new(), new()];

    // Step 4
    private string _coverLetter = string.Empty;

    // Step 5
    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;

    private void GoToStep(int step)
    {
        if (step <= _highestCompletedStep + 1 && !_submitted)
        {
            _errorMessage = null;
            _currentStep = step;
        }
    }

    private void PreviousStep()
    {
        _errorMessage = null;
        _currentStep--;
    }

    // ── Step 1 ──
    private async Task NextFromPersonalInfo()
    {
        _errorMessage = null;

        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _errorMessage = "Please fill in all required fields.";
            return;
        }

        _isValidating = true;
        try
        {
            var valid = await AppService.ValidateEmailAsync(_email);
            if (!valid)
            {
                _errorMessage = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            _isValidating = false;
        }

        CompleteAndAdvance(1);
    }

    // ── Step 2 ──
    private void AddWorkEntry() => _workEntries.Add(new WorkEntryModel());

    private void RemoveWorkEntry(int index)
    {
        if (_workEntries.Count > 1) _workEntries.RemoveAt(index);
    }

    private void UpdateWorkEntry(int index, WorkEntryModel entry) => _workEntries[index] = entry;

    private void NextFromWorkHistory()
    {
        _errorMessage = null;
        foreach (var entry in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title)
                || entry.StartDate == default || string.IsNullOrWhiteSpace(entry.Description))
            {
                _errorMessage = "Please fill in all required fields for every work entry.";
                return;
            }
        }
        CompleteAndAdvance(2);
    }

    // ── Step 3 ──
    private void AddReference()
    {
        if (_references.Count < 3) _references.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (_references.Count > 2) _references.RemoveAt(index);
    }

    private void UpdateReference(int index, ReferenceModel reference) => _references[index] = reference;

    private void NextFromReferences()
    {
        _errorMessage = null;
        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _errorMessage = "Please fill in all required fields for every reference.";
                return;
            }
        }
        CompleteAndAdvance(3);
    }

    // ── Step 4 ──
    private void NextFromCoverLetter()
    {
        _errorMessage = null;
        if (string.IsNullOrWhiteSpace(_coverLetter))
        {
            _errorMessage = "Please write a cover letter.";
            return;
        }
        CompleteAndAdvance(4);
    }

    // ── Step 5 ──
    private async Task SubmitApplication()
    {
        _isSubmitting = true;
        _errorMessage = null;

        try
        {
            var application = new JobApplication(
                new PersonalInfo(_fullName, _email, _phone, _address),
                new WorkHistory(_workEntries.Select(w =>
                    new WorkEntry(w.Company, w.Title, w.StartDate, w.IsCurrent ? null : w.EndDate, w.Description)).ToList()),
                _references.Select(r =>
                    new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                _coverLetter
            );

            _applicationId = await AppService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch
        {
            _errorMessage = "Submission failed. Please try again.";
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    private void CompleteAndAdvance(int step)
    {
        if (step > _highestCompletedStep)
            _highestCompletedStep = step;
        _currentStep = step + 1;
    }

    private static string FormatDate(DateTime date) =>
        date == default ? string.Empty : date.ToString("yyyy-MM-dd");

    private static string FormatDate(DateTime? date) =>
        date?.ToString("yyyy-MM-dd") ?? string.Empty;

    private static DateTime ParseDate(object? value) =>
        DateTime.TryParse(value?.ToString(), out var d) ? d : default;

    private static DateTime? ParseNullableDate(object? value) =>
        DateTime.TryParse(value?.ToString(), out var d) ? d : null;

    // Mutable models for form binding
    private record WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }

    private record ReferenceModel
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }
}

